var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`용이 되어야 해.`,JPN:`龍にならないと。`,ENG:`I must become a Dragon.`,TWN:`一定要變成龍！`},stage:{bg:`MAINSTREAM_7050010`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`용이 되지 않으면 이 고통에서 벗어날 수 없어.`,JPN:`龍にならなければ、この苦痛から抜け出せない。`,ENG:`I cannot escape this suffering unless I become a Dragon.`,TWN:`不變成龍就無法擺脫痛苦。`},stage:{bg:`MAINSTREAM_7050010`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`시윤아.`,JPN:`シリュウ。`,ENG:`My dear Shiyoon.`,TWN:`時雲，`},stage:{bg:`MAINSTREAM_7050010`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`엄마가 용이 되려면 용의 피가 더 필요하단다.`,JPN:`お母さんが龍になるためには龍の血がもっと必要なの。`,ENG:`Mommy needs more Dragon Blood to become a Dragon.`,TWN:`媽媽還需要更多的龍血才能變成龍。`},stage:{bg:`MAINSTREAM_7050010`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:null,text:{KOREA:`우리 시윤이는 착하니까…… 엄마한테 줄 거지?`,JPN:`シリュウはいい子だから……お母さんにくれるわよね？`,ENG:`You're a good boy… You'll help mommy out, right?`,TWN:`我們時雲這麼乖……一定會把血給媽媽的吧？`},stage:{bg:`MAINSTREAM_7050010`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:null,text:{KOREA:`그러니까…… 그러니까……`,JPN:`だから……だから……`,ENG:`Okay then…`,TWN:`所以……所以……`},stage:{bg:`MAINSTREAM_7050010`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ff3636>네 피를 내놔!</color>`,JPN:`<color=#ff3636>お前の血をよこせ！</color>`,ENG:`<color=#ff3636>Give me your blood!</color>`,TWN:`<color=#ff3636>把血給我！</color>`},stage:{bg:`MAINSTREAM_7050010`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`……허억!`,JPN:`……はっ！`,ENG:`…Gaah!`,TWN:`……嚇！`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`하아…… 하아……`,JPN:`はあ……はあ……`,ENG:`Huff, huff...`,TWN:`呼呼……呼呼……`},stage:{bg:`BACKSTREET`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`……자면서 계속 소리를 지르더군.`,JPN:`……何度もうなされていたようだな。`,ENG:`…You kept screaming in your sleep.`,TWN:`……你一直說夢話。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`요즘도 계속 악몽을 꾸나?`,JPN:`最近もずっと悪夢を見ているのか？`,ENG:`Do you still have nightmares?`,TWN:`最近還是很常做惡夢嗎？`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`네…….`,JPN:`はい……`,ENG:`Yes…`,TWN:`嗯……`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`저, 용혈이란 게 뭐죠?`,JPN:`あの、龍血とは何ですか？`,ENG:`Um, what is this "Dragon Blood?"`,TWN:`那個，龍血是什麼？`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`HILDE_FENRIR_NULL_NULL`,text:{KOREA:`……그 말은 또 어디서 들었지?`,JPN:`……それをどこで聞いた？`,ENG:`…Where did you hear about that?`,TWN:`……這個詞你從哪裡聽來的？`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`엄마가…… 계속 그 이야기를 했었어요.`,JPN:`お母さんが……ずっとその話をしていました。`,ENG:`My mom… She never stopped talking about it.`,TWN:`我媽媽……從以前就一直提到龍血。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`JOOSHIYOON_FENRIR_NULL_NULL`,text:{KOREA:`제 몸에 있는 용혈이 필요하다고…… 용이 되어야 한다고.`,JPN:`僕の体にある龍血が必要で……龍にならなければならない、と。`,ENG:`She said she needs Dragon Blood from me… That she needs to become a Dragon.`,TWN:`說他需要我體內的龍血……說她一定要變成龍。`},stage:{bg:`BACKSTREET`,slots:{L:null,C:{char_id:`HILDE_FENRIR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};